//go:generate go run gen.go

// Package awsrulesfn vendors AWS partition resolution data from
// aws-sdk-go-v2's internal awsrulesfn package, since Go's internal/
// visibility rule blocks importing it directly.
//
// partition.go and partitions.go are generated by gen.go — do not edit
// by hand. Re-run go generate after bumping aws-sdk-go-v2.
package awsrulesfn // import "github.com/amazon-contributing/opentelemetry-collector-contrib/override/aws/awsrulesfn"
